#include <algorithm>
#include <chrono>
#include <cstdint>
#include <fstream>
#include <iomanip>
#include <iostream>
#include <numeric>
#include <optional>
#include <queue>
#include <random>
#include <string>
#include <vector>

/**
 * Represents a point in the plane.
 *
 * Input: x and y coordinates in [0, 1].
 * Output: a lightweight immutable geometric point used to build nodes.
 */
struct Point {
    double x;
    double y;
};

/**
 * Represents a node in the Union-Find structure.
 *
 * Each node stores its coordinates, a parent pointer and the size of the
 * tree rooted at that node. Initially, every node is its own parent.
 */
struct Node {
    double x = 0.0;
    double y = 0.0;
    Node* parent = this;
    std::size_t subtree_size = 1;
};

/**
 * Represents an edge between two nodes.
 *
 * Input: two node pointers and the squared Euclidean distance between them.
 * Output: a comparable record usable by sort or priority_queue.
 */
struct Edge {
    Node* u = nullptr;
    Node* v = nullptr;
    double weight = 0.0;
};

/**
 * Comparator for edges ordered by increasing weight.
 */
struct EdgeGreater {
    bool operator()(const Edge& a, const Edge& b) const {
        return a.weight > b.weight;
    }
};

/**
 * Disjoint-set / Union-Find implementation with optional path compression.
 *
 * Input: nodes linked through parent pointers.
 * Output: support for find/union operations with union by size.
 */
class UnionFind {
public:
    /**
     * Finds the representative of a node.
     *
     * @param node Node whose root is required.
     * @param compress Whether to apply path compression.
     * @return Pointer to the root node.
     */
    static Node* find(Node* node, bool compress) {
        if (compress) {
            if (node->parent != node) {
                node->parent = find(node->parent, true);
            }
            return node->parent;
        }

        while (node->parent != node) {
            node = node->parent;
        }
        return node;
    }

    /**
     * Unites the sets containing two nodes using union by size.
     *
     * @param a First root node.
     * @param b Second root node.
     * @return True if a merge happened, false if both nodes were already in the same set.
     */
    static bool unite(Node* a, Node* b) {
        if (a == b) {
            return false;
        }
        if (a->subtree_size < b->subtree_size) {
            std::swap(a, b);
        }
        b->parent = a;
        a->subtree_size += b->subtree_size;
        return true;
    }
};

/**
 * Builds fresh nodes from a list of geometric points.
 *
 * Input: points with fixed coordinates.
 * Output: a vector of nodes whose parent pointers are self-referential.
 */
std::vector<Node> build_nodes(const std::vector<Point>& points) {
    std::vector<Node> nodes(points.size());
    for (std::size_t i = 0; i < points.size(); ++i) {
        nodes[i].x = points[i].x;
        nodes[i].y = points[i].y;
        nodes[i].parent = &nodes[i];
        nodes[i].subtree_size = 1;
    }
    return nodes;
}

/**
 * Computes the squared Euclidean distance between two nodes.
 *
 * Input: node coordinates.
 * Output: squared distance, which is the edge weight for this task.
 */
double squared_distance(const Node& a, const Node& b) {
    const double dx = a.x - b.x;
    const double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

/**
 * Builds all possible edges of the complete graph induced by a set of nodes.
 *
 * Input: node array.
 * Output: a vector with n(n-1)/2 edges, each holding pointers to its endpoints.
 */
std::vector<Edge> build_edges(std::vector<Node>& nodes) {
    const std::size_t n = nodes.size();
    std::vector<Edge> edges;
    edges.reserve(n * (n - 1) / 2);

    for (std::size_t i = 0; i < n; ++i) {
        for (std::size_t j = i + 1; j < n; ++j) {
            edges.push_back(Edge{&nodes[i], &nodes[j], squared_distance(nodes[i], nodes[j])});
        }
    }
    return edges;
}

/**
 * Runs Kruskal using a sorted array as the extraction structure.
 *
 * Input: nodes, path-compression flag.
 * Output: total MST weight and elapsed time in milliseconds.
 */
double kruskal_sorted(const std::vector<Point>& points, bool compress) {
    auto nodes = build_nodes(points);
    auto edges = build_edges(nodes);
    const auto start = std::chrono::steady_clock::now();

    std::sort(edges.begin(), edges.end(), [](const Edge& a, const Edge& b) {
        return a.weight < b.weight;
    });

    double total_weight = 0.0;
    std::size_t chosen = 0;
    for (const Edge& e : edges) {
        Node* ru = UnionFind::find(e.u, compress);
        Node* rv = UnionFind::find(e.v, compress);
        if (ru != rv) {
            UnionFind::unite(ru, rv);
            total_weight += e.weight;
            ++chosen;
            if (chosen + 1 == points.size()) {
                break;
            }
        }
    }

    const auto end = std::chrono::steady_clock::now();
    const std::chrono::duration<double, std::milli> elapsed = end - start;
    (void)total_weight;
    return elapsed.count();
}

/**
 * Runs Kruskal using a classic heap as the extraction structure.
 *
 * Input: points, path-compression flag.
 * Output: total MST weight and elapsed time in milliseconds.
 */
double kruskal_heap(const std::vector<Point>& points, bool compress) {
    auto nodes = build_nodes(points);
    auto edges = build_edges(nodes);
    const auto start = std::chrono::steady_clock::now();

    std::priority_queue<Edge, std::vector<Edge>, EdgeGreater> heap(EdgeGreater{}, std::move(edges));

    double total_weight = 0.0;
    std::size_t chosen = 0;
    while (!heap.empty() && chosen + 1 < points.size()) {
        Edge e = heap.top();
        heap.pop();
        Node* ru = UnionFind::find(e.u, compress);
        Node* rv = UnionFind::find(e.v, compress);
        if (ru != rv) {
            UnionFind::unite(ru, rv);
            total_weight += e.weight;
            ++chosen;
        }
    }

    const auto end = std::chrono::steady_clock::now();
    const std::chrono::duration<double, std::milli> elapsed = end - start;
    (void)total_weight;
    return elapsed.count();
}

/**
 * Generates a deterministic sequence of points in [0, 1]^2.
 *
 * Input: size n and seed.
 * Output: vector of n pseudorandom points.
 */
std::vector<Point> generate_points(std::size_t n, std::uint64_t seed) {
    std::mt19937_64 rng(seed);
    std::uniform_real_distribution<double> dist(0.0, 1.0);

    std::vector<Point> points;
    points.reserve(n);
    for (std::size_t i = 0; i < n; ++i) {
        points.push_back(Point{dist(rng), dist(rng)});
    }
    return points;
}

/**
 * Benchmarks one size over several random trials and writes a CSV row set.
 *
 * Input: size n, number of trials, output stream.
 * Output: writes one record per algorithm and trial.
 */
void benchmark_size(std::size_t n, std::size_t trials, std::ostream& out) {
    for (std::size_t t = 0; t < trials; ++t) {
        const std::uint64_t seed = 0xC0FFEEULL ^ (static_cast<std::uint64_t>(n) << 20) ^ t;
        const std::vector<Point> points = generate_points(n, seed);

        const double sorted_pc = kruskal_sorted(points, true);
        const double heap_pc = kruskal_heap(points, true);
        const double sorted_nopc = kruskal_sorted(points, false);
        const double heap_nopc = kruskal_heap(points, false);

        out << n << ',' << t << ',' << "sorted_compression" << ',' << std::fixed << std::setprecision(6) << sorted_pc << '\n';
        out << n << ',' << t << ',' << "heap_compression" << ',' << std::fixed << std::setprecision(6) << heap_pc << '\n';
        out << n << ',' << t << ',' << "sorted_no_compression" << ',' << std::fixed << std::setprecision(6) << sorted_nopc << '\n';
        out << n << ',' << t << ',' << "heap_no_compression" << ',' << std::fixed << std::setprecision(6) << heap_nopc << '\n';
    }
}

/**
 * Computes the benchmark sizes requested by the statement.
 *
 * Assumption used in this solution: the intended sizes are powers of two,
 * from 2^5 to 2^12, matching the textual mention of 25 ... 212.
 *
 * Output: list of input sizes.
 */
std::vector<std::size_t> benchmark_sizes() {
    std::vector<std::size_t> sizes;
    for (std::size_t p = 5; p <= 12; ++p) {
        sizes.push_back(static_cast<std::size_t>(1ULL << p));
    }
    return sizes;
}

/**
 * Program entry point.
 *
 * Input: optional output path for the CSV file.
 * Output: benchmark file with all recorded times.
 */
int main(int argc, char** argv) {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    const std::string output_path = (argc >= 2) ? argv[1] : "results.csv";
    std::ofstream out(output_path);
    if (!out) {
        std::cerr << "Error: could not open output file '" << output_path << "'.\n";
        return 1;
    }

    out << "n,trial,algorithm,time_ms\n";
    const auto sizes = benchmark_sizes();
    for (std::size_t n : sizes) {
        benchmark_size(n, 5, out);
    }

    std::cout << "Benchmark written to " << output_path << '\n';
    return 0;
}
